bool operator <(tip a, tip b)

{

  return a.val<b.val;

}

int i,n,h;

int a[NMAX];

int main()

{cin>>n>>h;

 for(i=1;i<=h;i++)

    {

     int x;

     cin>>x;

     H.push({x,i});

    }

  while(H.size()>=2)

        {

         tip x,y;

         x=H.top();

         H.pop();

         y=H.top();

         H.pop();

         if(n<=2* y.val)

         {cout<<0;return 0;}

         else

         {n-=2*y.val;

          x.val-=y.val;

          if(x.val)

             H.push(x);

         }



        }

  if(H.size())

      cout<<H.top().val-1;

      else

        cout<<0;

     return 0;

}

