using namespace std;



int main() {

    ios_base::sync_with_stdio(false);

    cin.tie(nullptr);



    int s, n;

    cin >> s >> n;



    priority_queue<pair<int, int>> pq;

    for (int i = 0; i < n; i++) {

        int x; cin >> x;

        pq.emplace(x, i);

    }



    int cnt = 0, last = -1;

    for (int i = 0; i < s; i++) {

        auto top = pq.top(); pq.pop();

        if (top.second == last && !pq.empty()) {

            auto cpy = top;

            top = pq.top(); pq.pop();

            pq.push(cpy);

        }

        if (top.first > 1)

            pq.emplace(top.first - 1, top.second);

        if (top.second == last)

            cnt++;

        last = top.second;

    }



    cout << cnt << '\n';

    return 0;

}

