typedef long long int64;

inline int read(int f = 1, int x = 0, char ch = ' ')

{

    while(!isdigit(ch = getchar())) if(ch == '-') f = -1;

    while(isdigit(ch)) x = x*10+ch-'0', ch = getchar();

    return f*x;

}

const int N = 2e5+5;

int n, p[N], s[N], top, f[N], g[N];

int64 ans;

int main()

{

    n = read(); 

    for(int i = 1; i <= n; ++i) p[i] = read();

    top = 0;

    for(int i = 1; i <= n; ++i) 

    {

        while(top&&p[s[top]] > p[i]) --top;

        f[i] = i-s[top], s[++top] = i;

    }

    top = 0; s[0] = n+1;

    for(int i = n; i; --i)

    {

        while(top&&p[s[top]] > p[i]) --top;

        g[i] = s[top]-i, s[++top] = i;

    }

    for(int i = 1; i <= n; ++i) ans += 1ll*f[i]*g[i]*p[i];

    printf("%lld\n", ans);

    return 0;

}

